import { useEffect, useState } from "react";

import { Modal } from "@material-ui/core";
import { Paper, Tab, Tabs, MobileStepper, Box } from "@mui/material";
import { KeyboardArrowLeft, KeyboardArrowRight } from "@mui/icons-material";

import { BookCardProps } from "models";
import { TabPanel } from "components/tab_panel";
import { CustomButton } from "components/custom_button";
import { eGlobalConstants, PREFIX_URL } from "global_constants";

import { BookOverview } from "pages/home/features/book_list/book_card/product/overview";
import { BookSpecifications } from "pages/home/features/book_list/book_card/product/specification";
import { BookReviews } from "pages/home/features/book_list/book_card/product/reviews";

interface BookModalProps {
  open: boolean;
  bookDetails: BookCardProps;
  closeHandle: () => void;
}

export function BookModal({
  open,
  bookDetails,
  closeHandle,
}: BookModalProps): JSX.Element {
  const [value, setValue] = useState(0);
  const [overViewExists, setOverViewExists] = useState(false);
  const [specExists, setSpecExists] = useState(false);
  const [reviewExists, setReviewExists] = useState(false);
  const [thumbnails, setThumbnails] = useState<string[]>([]);
  // const [currentThumbnail, setCurrentThumbnail] = useState("");
  const [activeStep, setActiveStep] = useState(0);

  const buildThumbnailList = () => {
    let thumbnailList = [];
    thumbnailList.push(
      eGlobalConstants.BOOK_CARD_MAIN_THUMBNAIL + bookDetails.thumbnail
    );
    for (var pic of bookDetails.sub_thumbnails) {
      thumbnailList.push(eGlobalConstants.BOOK_CARD_SUB_THUMBNAILS + pic);
    }
    setThumbnails(thumbnailList);
  };

  useEffect(() => {
    if (
      (bookDetails.title && bookDetails.title.length > 0) ||
      (bookDetails.description && bookDetails.description.length > 0)
    )
      setOverViewExists(true);
    if (bookDetails.specifications && bookDetails.specifications.length > 0)
      setSpecExists(true);
    if (bookDetails.reviews && bookDetails.reviews.review_list.length > 0)
      setReviewExists(true);

    console.log(bookDetails);
    buildThumbnailList();
  }, [bookDetails]);

  const handleChange = (event: React.SyntheticEvent, newValue: number) => {
    setValue(newValue);
  };

  const onPrevClick = () => {
    setActiveStep((currentStep) => currentStep - 1);
  };

  const onNextClick = () => {
    console.log("OnNextClick");
    setActiveStep((currentStep) => currentStep + 1);
  };

  return (
    <Modal
      open={open}
      onClose={closeHandle}
      style={{
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        transition: "all 0.8s",
      }}
    >
      <Paper
        sx={{
          width: 1300,
          px: 4,
          transition: "all 0.8s",
          // backgroundColor: "rgba(255,255,255,0.8)",
        }}
      >
        {(overViewExists || specExists || reviewExists) && (
          <Box
            sx={{ height: 700, display: "flex", alignItems: "center", gap: 5 }}
          >
            <Box p={2}>
              <img
                src={PREFIX_URL + thumbnails.at(activeStep)}
                alt="book"
                style={{ width: 350 }}
              />
              <MobileStepper
                variant="dots"
                steps={thumbnails.length}
                position="static"
                activeStep={activeStep}
                sx={{ maxWidth: 400, flexGrow: 1 }}
                nextButton={
                  <CustomButton
                    component="Button"
                    onClick={onNextClick}
                    disabled={activeStep === thumbnails.length - 1}
                  >
                    <KeyboardArrowRight />
                  </CustomButton>
                }
                backButton={
                  <CustomButton
                    component="Button"
                    onClick={onPrevClick}
                    disabled={activeStep === 0}
                  >
                    <KeyboardArrowLeft />
                  </CustomButton>
                }
              />
            </Box>
            <Box sx={{ width: "100%", height: 700 }}>
              <Tabs
                value={value}
                onChange={handleChange}
                variant="fullWidth"
                sx={{ pt: 2 }}
              >
                {overViewExists && <Tab label="OverView" />}
                {specExists && <Tab label="Specification" />}
                {reviewExists && <Tab label="Reviews" />}
              </Tabs>
              <div style={{ padding: 30 }}>
                {overViewExists && (
                  <TabPanel value={value} index={0}>
                    <BookOverview bookDetails={bookDetails} />
                  </TabPanel>
                )}
                {specExists && (
                  <TabPanel value={value} index={1}>
                    <BookSpecifications
                      bookDetails={bookDetails.specifications}
                    />
                  </TabPanel>
                )}
                {reviewExists && (
                  <TabPanel value={value} index={2}>
                    <BookReviews bookDetails={bookDetails.reviews} />
                  </TabPanel>
                )}
              </div>
            </Box>
          </Box>
        )}
      </Paper>
    </Modal>
  );
}
