import { useSelector } from "react-redux";
import { Fragment } from "react/jsx-runtime";

import { Box, Card, Divider, Grid2, Paper } from "@mui/material";
import ShoppingCartIcon from "@mui/icons-material/ShoppingCart";
import SearchOffIcon from "@mui/icons-material/SearchOff";
import ShoppingCartCheckoutIcon from "@mui/icons-material/ShoppingCartCheckout";

import { RootState } from "store";
import { CustomTypography } from "components/custom_typography";
import { eGlobalConstants, PREFIX_URL } from "global_constants";
import { PriceCard } from "components/price_card";
import { CustomButton } from "components/custom_button";

export function Cart(): JSX.Element {
  const cartSlice = useSelector((state: RootState) => state.dataSlice.cartMap);

  return (
    <Box display={"flex"} justifyContent={"center"}>
      {cartSlice && cartSlice.length > 0 ? (
        <Card
          sx={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            width: "fit-content",
            mt: 5,
          }}
        >
          <Grid2 container direction={"column"} p={2}>
            <Grid2
              display={"flex"}
              justifyContent={"center"}
              alignItems={"center"}
              gap={2}
            >
              <ShoppingCartIcon sx={{ color: "gray", fontSize: 40 }} />
              <CustomTypography variant="h2" sx={{ color: "gray" }}>
                Cart
              </CustomTypography>
            </Grid2>
            <Divider />
            <Grid2
              container
              spacing={{ xs: 2, md: 3, lg: 3 }}
              columns={{ xs: 4, sm: 8, md: 12, lg: 9 }}
              sx={{
                position: "relative",
                overflow: "auto",
                maxHeight: 600,
                width: 1200,
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                p: 2,
              }}
            >
              {cartSlice.map((item, index) => (
                <Grid2 key={index} size={{ xs: 2, sm: 4, md: 4, lg: 4 }}>
                  <Fragment>
                    {item && (
                      <Paper sx={{ width: "100%" }}>
                        <Grid2 container display={"flex"} alignItems={"center"}>
                          <Grid2
                            size={{ xs: 2, sm: 4, md: 4, lg: 3 }}
                            display={"flex"}
                            alignItems={"center"}
                          >
                            <img
                              src={
                                PREFIX_URL +
                                eGlobalConstants.BOOK_CARD_MAIN_THUMBNAIL +
                                item.bookDetails.thumbnail
                              }
                              alt="book"
                              style={{ width: 100, padding: 10 }}
                            />
                            <Divider
                              orientation="vertical"
                              variant="fullWidth"
                              flexItem
                            />
                          </Grid2>
                          <Grid2 size={9}>
                            <CustomTypography variant="h5" sx={{ padding: 1 }}>
                              {item.bookDetails.title}
                            </CustomTypography>
                            <Divider variant="fullWidth" />
                            <PriceCard
                              bookDetails={item.bookDetails}
                              isCartOperation
                            />
                          </Grid2>
                        </Grid2>
                      </Paper>
                    )}
                  </Fragment>
                </Grid2>
              ))}
            </Grid2>
            <Divider />
            <Grid2 display={"flex"} justifyContent={"right"} mt={2}>
              <CustomButton
                component="Button"
                startIcon={<ShoppingCartCheckoutIcon sx={{ color: "white" }} />}
                sx={{
                  backgroundColor: "#02A9F4",
                  padding: 1.5,
                }}
              >
                <CustomTypography variant="button" sx={{ color: "white" }}>
                  CheckOut
                </CustomTypography>
              </CustomButton>
            </Grid2>
          </Grid2>
        </Card>
      ) : (
        <Box display={"flex"} alignItems={"center"} gap={2} p={30}>
          <SearchOffIcon sx={{ color: "grey", fontSize: 100 }} />
          <CustomTypography variant="h2" sx={{ color: "grey" }}>
            No items found in Cart
          </CustomTypography>
        </Box>
      )}
    </Box>
  );
}
