import { Fragment, useEffect, useState } from "react";

import { BookList } from "./book_list";
import { CategoryContent } from "models";

// TODO: this is a mock, remove
import BookListJson from "mocks/home_page_data.json";

export function BookDashboard(): JSX.Element {
  const [pageContent, setPageContent] = useState<CategoryContent[]>([]);
  const [resizeEventObserved, setResizeEventObserved] = useState(
    window.devicePixelRatio
  );

  useEffect(() => {
    window.addEventListener("resize", () => {
      setResizeEventObserved(window.devicePixelRatio);
    });

    return () => {
      window.removeEventListener("resize", () => {
        setResizeEventObserved(window.devicePixelRatio);
      });
    };
  }, []);

  useEffect(() => {
    var contents: CategoryContent[] = [];
    contents = JSON.parse(JSON.stringify(BookListJson.page_contents));
    console.log(contents);
    setPageContent(contents);
  }, []);

  console.log(resizeEventObserved);

  return (
    <Fragment>
      {pageContent.map((category: CategoryContent, index: any) => (
        <BookList key={index} content={category} />
      ))}
    </Fragment>
  );
}
