import { useState } from "react";
import { useSelector } from "react-redux";
import { useNavigate } from "react-router-dom";

import { Grid } from "@material-ui/core";
import { AppBar, Badge, ButtonGroup } from "@mui/material";

import { RootState } from "store";
import { DrawerList } from "./drawer";
import { Search } from "./search";
import { eGlobalConstants, PREFIX_URL } from "global_constants";
import { CustomButton } from "components/custom_button";
import { buttonGroup, ButtonGroupProp, eButtonList } from "./nav_buttons";

function Navbar(): JSX.Element {
  const [toggleDrawer, setToggleDrawer] = useState(false);
  const navigate = useNavigate();
  const itemsInCart = useSelector(
    (state: RootState) => state.dataSlice.cartMap.length
  );

  const handleDrawerOpen = () => {
    setToggleDrawer(true);
  };
  const handleDrawerClose = () => {
    setToggleDrawer(false);
  };

  const handleButtonClick = (buttonID: eButtonList) => {
    switch (buttonID) {
      case eButtonList.CART:
        navigate("/cart/");
        break;
      case eButtonList.OPTS:
        handleDrawerOpen();
        break;
      case eButtonList.ORDERS:
        break;
      case eButtonList.WISHLIST:
        break;
      case eButtonList.LOGIN:
        break;
    }
  };

  return (
    <AppBar
      position="sticky"
      sx={{
        backgroundImage: `url(${
          PREFIX_URL + "/assets/nav_bar/nav_background.png"
        })`,
      }}
    >
      <Grid
        container
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          backgroundColor: "rgba(0, 0, 0, 0)",
          paddingLeft: "30px",
        }}
      >
        <Grid item lg={3} style={{ display: "flex" }}>
          <img
            src={PREFIX_URL + eGlobalConstants.BOOKISH_LOGO}
            alt="logo"
            width={300}
            onClick={() => navigate("/")}
          />
        </Grid>
        <Grid item lg={5}>
          <Search />
        </Grid>
        <Grid item lg={2} style={{ textAlign: "left", paddingLeft: 50 }}>
          <ButtonGroup variant="text" color="primary" sx={{ gap: 5 }}>
            {buttonGroup.map((value: ButtonGroupProp, index: any) => (
              <div key={index}>
                <CustomButton
                  component={"IconButton"}
                  onClick={() => handleButtonClick(value.buttonGroup.buttonId)}
                >
                  <Badge
                    badgeContent={itemsInCart}
                    color="primary"
                    invisible={value.buttonGroup.buttonId !== eButtonList.CART}
                    showZero
                  >
                    <value.buttonGroup.icon
                      sx={{ fontSize: 40, color: "white" }}
                    />
                  </Badge>
                </CustomButton>
                {value.drawer &&
                  value.drawer.options &&
                  DrawerList(
                    value.drawer,
                    toggleDrawer,
                    handleDrawerClose,
                    handleDrawerOpen
                  )}
              </div>
            ))}
          </ButtonGroup>
        </Grid>
      </Grid>
    </AppBar>
  );
}

export default Navbar;
