import { Fragment, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

import { Box } from "@mui/material";
import InfoIcon from "@mui/icons-material/Info";
import { Button, Grid } from "@material-ui/core";

import { AdsJsonModel } from "models";
import AdJson from "mocks/advertisements.json";
import { CustomTypography } from "components/custom_typography";
import { eGlobalConstants, PREFIX_URL } from "global_constants";

export function Advertisement(): JSX.Element {
  const [imageId, setImageId] = useState(-1);
  const navigate = useNavigate();
  const [adsList, setAdsList] = useState<AdsJsonModel[]>([]);
  useEffect(() => {
    var jsonObj: AdsJsonModel[] = JSON.parse(JSON.stringify(AdJson.AdsList));
    setAdsList(jsonObj);
  }, []);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setImageId((imageId + 1) % adsList?.length);
    }, 5000);
    return () => {
      clearInterval(intervalId);
    };
  }, [imageId, adsList]);

  const handleTransitionEnd = () => {
    // console.log(JSON.stringify(adsList));
  };

  return (
    <Box
      sx={{
        display: "flex",
        width: `${adsList.length * 100}%`,
        transition: "transform 0.8s ease-in-out",
        transform: `translateX(-${imageId * (100 / adsList.length)}%)`,
      }}
      onTransitionEnd={handleTransitionEnd}
    >
      {adsList.map((value: AdsJsonModel, index: any) => (
        <Fragment key={index}>
          <Box
            width={"100%"}
            height={450}
            sx={{
              display: "flex",
              background: `url(${
                PREFIX_URL + eGlobalConstants.ADS_COVER + value.coverImg
              }) center/cover no-repeat`,
            }}
          >
            <Grid container>
              <Grid item lg={10} />
              <Grid
                item
                lg={2}
                style={{
                  display: "flex",
                  justifyContent: "center",
                  alignItems: "end",
                }}
              >
                <Button
                  startIcon={<InfoIcon sx={{ color: "white" }} />}
                  style={{
                    backgroundColor: "rgba(255,255,255,0.4)",
                    height: 50,
                    margin: 20,
                    borderRadius: 10,
                    padding: 20,
                  }}
                  onClick={() => navigate(value.routeOnClick)}
                >
                  <CustomTypography variant="button" sx={{ color: "white" }}>
                    More Info
                  </CustomTypography>
                </Button>
              </Grid>
            </Grid>
          </Box>
        </Fragment>
      ))}
    </Box>
  );
}
