import { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";

import { Box } from "@material-ui/core";
import { TablePagination } from "@mui/material";

import { RootState, setPagination } from "store";

interface PageinateProps {
  count: number;
  rowsPerPage: number;
}
export const Paginate = ({ count, rowsPerPage }: PageinateProps) => {
  const dispatch = useDispatch();
  const paginationSlice = useSelector(
    (state: RootState) => state.dataSlice.pagination
  );

  const handleChangePage = (event: unknown, newPage: number) => {
    let pagination = {
      page: newPage,
      rowsPerPage: paginationSlice.rowsPerPage,
    };
    dispatch(setPagination(pagination));
  };

  useEffect(() => {
    let pagination = {
      page: 0,
      rowsPerPage: rowsPerPage,
    };
    dispatch(setPagination(pagination));
  }, [dispatch, rowsPerPage]);

  return (
    <Box>
      <TablePagination
        rowsPerPageOptions={[5]}
        component="div"
        count={count}
        rowsPerPage={paginationSlice.rowsPerPage}
        page={paginationSlice.page}
        onPageChange={handleChangePage}
      />
    </Box>
  );
};
