import { configureStore, createSlice, PayloadAction } from "@reduxjs/toolkit";

import { AlertColor } from "@mui/material";

import { BookCardProps } from "models";

interface PagnationProps {
  rowsPerPage: number;
  page: number;
}

export interface CartMap {
  bookDetails: BookCardProps;
  book_count: number;
}

export interface BookCountMap {
  book_uuid: string;
  book_count: number;
}

interface ReduxStateData {
  pagination: PagnationProps;
  wishList: string[];
  bookCountMap: BookCountMap[];
  cartMap: CartMap[];
  do_alert: Alert_props;
}

interface Alert_props {
  open: boolean;
  message: string;
  severity: AlertColor;
}

// Initial state
const initialState: ReduxStateData = {
  pagination: { rowsPerPage: 3, page: 0 },
  wishList: [],
  bookCountMap: [],
  cartMap: [],
  do_alert: { message: "", open: false, severity: "info" },
};

const dataSlice = createSlice({
  name: "DataSlice",
  initialState,
  reducers: {
    setPagination: (state, action: PayloadAction<PagnationProps>) => {
      state.pagination = {
        page: action.payload.page,
        rowsPerPage: action.payload.rowsPerPage,
      };
    },
    setWishList: (state, action: PayloadAction<string[]>) => {
      state.wishList = action.payload;
    },
    updateCart: (state, action: PayloadAction<CartMap[]>) => {
      state.cartMap = action.payload;
    },
    setOrderCount: (state, action: PayloadAction<BookCountMap[]>) => {
      state.bookCountMap = action.payload;
    },
    setDoAlert: (state, action: PayloadAction<Alert_props>) => {
      state.do_alert = action.payload;
    },
  },
});

const store = configureStore({
  reducer: {
    dataSlice: dataSlice.reducer,
  },
});

export const {
  setPagination,
  setWishList,
  updateCart,
  setOrderCount,
  setDoAlert,
} = dataSlice.actions;
export type RootState = ReturnType<typeof store.getState>;
export default store;
