import { useSelector, useDispatch } from "react-redux";
import { Alert, Snackbar } from "@mui/material";
import { CustomTypography } from "components/custom_typography";
import { RootState, setDoAlert } from "store";

export const CustomAlert = () => {
  const do_alert = useSelector((state: RootState) => state.dataSlice.do_alert);
  const dispatch = useDispatch();

  return (
    <Snackbar
      open={do_alert.open}
      autoHideDuration={5000}
      onClose={() =>
        dispatch(setDoAlert({ open: false, message: "", severity: "info" }))
      }
      anchorOrigin={{ vertical: "bottom", horizontal: "right" }}
    >
      <Alert
        severity={do_alert.severity}
        sx={{ display: "flex", alignItems: "center" }}
      >
        <CustomTypography sx={{ fontSize: 18 }}>
          {do_alert.message}
        </CustomTypography>
      </Alert>
    </Snackbar>
  );
};
