import { SxProps } from "@mui/system";
import { Typography } from "@mui/material";
import { Variant } from "@mui/material/styles/createTypography";

interface TypograpyProps {
  variant?: "inherit" | Variant | undefined;
  sx?: SxProps;
  children?: any;
}

export const CustomTypography = ({ sx, variant, children }: TypograpyProps) => {
  const defaultProps = {
    fontFamily: "EB Garamond",
    ...sx,
  };
  return (
    <Typography variant={variant} sx={defaultProps}>
      {children}
    </Typography>
  );
};
