import { useSelector } from "react-redux";

import { Box } from "@material-ui/core";
import {
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
} from "@mui/material";

import { Specifications } from "models";
import { CustomTypography } from "components/custom_typography";
import { Paginate } from "components/pagination";
import { RootState } from "store";

interface SpecProps {
  bookDetails: Specifications[];
}

export const BookSpecifications = ({ bookDetails }: SpecProps): JSX.Element => {
  const paginationSlice = useSelector(
    (state: RootState) => state.dataSlice.pagination
  );

  return (
    <Box height={400}>
      <TableContainer component={Paper}>
        <Table stickyHeader>
          <TableHead>
            <TableRow>
              <TableCell>
                <CustomTypography
                  variant="h5"
                  sx={{ fontFamily: "EB Garamond" }}
                >
                  Specification
                </CustomTypography>
              </TableCell>
              <TableCell align="left">
                <CustomTypography
                  variant="h5"
                  sx={{ fontFamily: "EB Garamond" }}
                >
                  Details
                </CustomTypography>
              </TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {bookDetails
              .slice(
                paginationSlice.page * paginationSlice.rowsPerPage,
                paginationSlice.page * paginationSlice.rowsPerPage +
                  paginationSlice.rowsPerPage
              )
              .map((spec: Specifications, index: any) => (
                <TableRow key={index}>
                  <TableCell component="th" scope="row">
                    <CustomTypography
                      variant="subtitle1"
                      sx={{ fontFamily: "EB Garamond", fontSize: 20 }}
                    >
                      {spec.name}
                    </CustomTypography>
                  </TableCell>
                  <TableCell align="left">
                    <CustomTypography
                      variant="subtitle1"
                      sx={{ fontFamily: "EB Garamond", fontSize: 20 }}
                    >
                      {spec.value}
                    </CustomTypography>
                  </TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>
      </TableContainer>
      <Paginate count={bookDetails.length} rowsPerPage={5} />
    </Box>
  );
};
