import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";

import { Box, TextField } from "@mui/material";
import AddCircleOutlineIcon from "@mui/icons-material/AddCircleOutline";
import RemoveCircleOutlineIcon from "@mui/icons-material/RemoveCircleOutline";

import { BookCardProps } from "models";
import { CustomButton } from "components/custom_button";
import { RootState, setOrderCount, updateCart } from "store";

interface NumberStepperProps {
  bookDetails: BookCardProps;
  isCartOperation: boolean;
  resetCounter?: boolean;
}

enum eNumberOfItems {
  Increement,
  Decreement,
}

export function NumberStepper({
  bookDetails,
  isCartOperation,
  resetCounter = false,
}: NumberStepperProps): JSX.Element {
  const dispatch = useDispatch();
  const [countValue, setCountValue] = useState(1);
  const [counterClicked, setCounterClicked] = useState(false);
  const cartMap = useSelector((state: RootState) => state.dataSlice.cartMap);
  const bookCountMap = useSelector(
    (state: RootState) => state.dataSlice.bookCountMap
  );

  const handleButtonClick = (button: eNumberOfItems) => {
    setCounterClicked(true);
    if (button === eNumberOfItems.Increement) {
      setCountValue((countValue) => countValue + 1);
    } else if (button === eNumberOfItems.Decreement) {
      if (countValue > 1) setCountValue((countValue) => countValue - 1);
    }
  };

  const handleChangeCount = (event: any, newValue: number) => {
    setCountValue(newValue);
  };

  const fetchCountValue = () => {
    if (isCartOperation) {
      let found = cartMap.find(
        (item) => item.bookDetails.uuid === bookDetails.uuid
      );
      if (found) setCountValue(found.book_count);
    }
  };

  // Fetch the count value from cart for a cart operation.
  useEffect(() => {
    fetchCountValue();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Resetting should be done the item has currently been added to cart at this moment.
  useEffect(() => {
    if (resetCounter) setCountValue(1);
  }, [resetCounter]);

  const updateCartMap = () => {
    var updatedCartMap = [...cartMap];
    let ele_index = updatedCartMap.findIndex(
      (state_item) => state_item.bookDetails.uuid === bookDetails.uuid
    );
    let state_item = updatedCartMap.at(ele_index);
    if (state_item) {
      let newItem = { ...state_item, book_count: countValue };
      updatedCartMap.splice(ele_index, 1, newItem);
    }
    dispatch(updateCart(updatedCartMap));
  };

  const updateBookCountMap = () => {
    var updatedBookCountMap = [...bookCountMap];
    let ele_index = updatedBookCountMap.findIndex(
      (state_item) => state_item.book_uuid === bookDetails.uuid
    );
    if (ele_index === -1) {
      updatedBookCountMap.push({
        book_uuid: bookDetails.uuid,
        book_count: countValue,
      });
    } else {
      let state_item = updatedBookCountMap.at(ele_index);
      if (state_item) {
        let newItem = { ...state_item, book_count: countValue };
        updatedBookCountMap.splice(ele_index, 1, newItem);
      }
    }
    dispatch(setOrderCount(updatedBookCountMap));
  };

  useEffect(() => {
    // Only update the map when the counter buttons are clicked.
    if (!counterClicked) return;
    setCounterClicked(false);

    // If the operation is from Cart page then update the count in cart itself.
    if (isCartOperation) {
      updateCartMap();
      return;
    }
    // If the operation is not from Cart page then update the temporary map.
    updateBookCountMap();
  }, [countValue, counterClicked, dispatch]); // eslint-disable-line react-hooks/exhaustive-deps

  return (
    <Box display={"flex"} alignItems={"center"}>
      <CustomButton
        component="IconButton"
        onClick={() => handleButtonClick(eNumberOfItems.Decreement)}
      >
        <RemoveCircleOutlineIcon sx={{ fontSize: 20 }} />
      </CustomButton>
      <TextField
        size="small"
        sx={{ width: 45 }}
        value={countValue}
        onChange={() => handleChangeCount}
        slotProps={{
          input: {
            readOnly: true,
            inputProps: {
              maxLength: 2,
            },
          },
        }}
      />
      <CustomButton
        component="IconButton"
        onClick={() => handleButtonClick(eNumberOfItems.Increement)}
      >
        <AddCircleOutlineIcon sx={{ fontSize: 20 }} />
      </CustomButton>
    </Box>
  );
}
