import ShoppingCartRoundedIcon from "@mui/icons-material/ShoppingCartRounded";
import AccountCircleIcon from "@mui/icons-material/AccountCircle";
import SettingsRoundedIcon from "@mui/icons-material/SettingsRounded";
import ReorderRoundedIcon from "@mui/icons-material/ReorderRounded";
import FavoriteRoundedIcon from "@mui/icons-material/FavoriteRounded";

export interface ButtonProp {
  buttonId: eButtonList;
  buttonName: string;
  icon: ({ sx }: any) => JSX.Element;
}

export interface DrawerProp {
  options: ButtonProp[];
}

export interface ButtonGroupProp {
  buttonGroup: ButtonProp;
  drawer?: DrawerProp;
}

export enum eButtonList {
  CART,
  OPTS,
  ORDERS,
  WISHLIST,
  LOGIN,
  ACCOUNT,
}

export const buttonGroup: ButtonGroupProp[] = [
  {
    buttonGroup: {
      buttonId: eButtonList.CART,
      buttonName: "Cart",
      icon: ({ sx }: any) => (
        <ShoppingCartRoundedIcon color="primary" sx={sx} />
      ),
    },
  },
  {
    buttonGroup: {
      buttonId: eButtonList.OPTS,
      buttonName: "Options",
      icon: ({ sx }: any) => <SettingsRoundedIcon color="primary" sx={sx} />,
    },
    drawer: {
      options: [
        {
          buttonId: eButtonList.ORDERS,
          buttonName: "Orders",
          icon: ({ sx }: any) => <ReorderRoundedIcon color="primary" sx={sx} />,
        },
        {
          buttonId: eButtonList.WISHLIST,
          buttonName: "WishList",
          icon: ({ sx }: any) => (
            <FavoriteRoundedIcon color="primary" sx={sx} />
          ),
        },
        {
          buttonId: eButtonList.ACCOUNT,
          buttonName: "Account",
          icon: ({ sx }: any) => <AccountCircleIcon color="primary" sx={sx} />,
        },
      ],
    },
  },
  {
    buttonGroup: {
      buttonId: eButtonList.LOGIN,
      buttonName: "Login",
      icon: ({ sx }: any) => <AccountCircleIcon color="primary" sx={sx} />,
    },
  },
];
