import { useEffect, useState } from "react";
import { useDispatch, useSelector } from "react-redux";

import { Box, Grid2, SxProps, AlertColor } from "@mui/material";
import RemoveShoppingCartIcon from "@mui/icons-material/RemoveShoppingCart";
import AddShoppingCartSharpIcon from "@mui/icons-material/AddShoppingCartSharp";

import { BookCardProps } from "models";
import { CustomButton } from "components/custom_button";
import { NumberStepper } from "components/number_stepper";
import { CustomTypography } from "components/custom_typography";
import { BookCountMap, RootState, setDoAlert, updateCart } from "store";
import { eGlobalConstants } from "global_constants";

interface PriceCardProps {
  bookDetails: BookCardProps;
  isCartOperation?: boolean;
  sx?: SxProps;
}

export const PriceCard = ({
  bookDetails,
  sx,
  isCartOperation = false,
}: PriceCardProps) => {
  const [discount, setDiscount] = useState(false);
  const [resetCounterValue, setResetCounterValue] = useState(false);
  const dispatch = useDispatch();
  const cartMap = useSelector((state: RootState) => state.dataSlice.cartMap);
  const bookCountMap = useSelector(
    (state: RootState) => state.dataSlice.bookCountMap
  );

  useEffect(() => {
    if (bookDetails?.accounting?.discount_percent) {
      setDiscount(true);
    }
  }, [bookDetails?.accounting]);

  const getCountFromBookCountMap = (indexInCart: number) => {
    let index_in_book_count_map = bookCountMap.findIndex(
      (itr) => itr.book_uuid === bookDetails.uuid
    );

    // Check if bookCountMap has this book. If yes we have to update the bookCount with this value as well.
    let item_of_book_count_map: BookCountMap | undefined;
    if (index_in_book_count_map !== -1) {
      item_of_book_count_map = bookCountMap.at(indexInCart);
      if (item_of_book_count_map) {
        return item_of_book_count_map.book_count;
      }
    }
    return 1;
  };

  const updateCartMap = () => {
    let updatedCartMap = [...cartMap];
    let index_in_cart_map = updatedCartMap.findIndex(
      (state_item) => state_item.bookDetails.uuid === bookDetails.uuid
    );

    let bookCount_in_bookCountMap = getCountFromBookCountMap(index_in_cart_map);
    if (index_in_cart_map === -1) {
      updatedCartMap.push({
        bookDetails: bookDetails,
        book_count: bookCount_in_bookCountMap,
      });
      dispatch(updateCart(updatedCartMap));
      return true;
    }
    return false;
  };

  const Notify = (message: string, severity: AlertColor) => {
    dispatch(
      setDoAlert({
        open: true,
        message: message,
        severity: severity,
      })
    );
  };

  const handleAddToCart = () => {
    if (!updateCartMap()) {
      Notify("Item Already In Cart!", "info");
    } else {
      Notify("Added to Cart!", "success");
    }
    setResetCounterValue(true);
  };

  const handleRemoveFromCart = () => {
    let _cartMap = [...cartMap];
    let ele_index = _cartMap.findIndex(
      (state_item) => state_item.bookDetails.uuid === bookDetails.uuid
    );
    if (ele_index !== -1) {
      let state_item = _cartMap.at(ele_index);
      if (state_item) {
        let updatedMap = _cartMap.filter(
          (item) => item.bookDetails.uuid !== state_item?.bookDetails.uuid
        );
        dispatch(updateCart(updatedMap));
      }
    }
  };

  return (
    <>
      <Grid2 container alignItems={"center"} p={2} sx={sx}>
        <Grid2 size={5}>
          <Box sx={{ display: "flex", gap: 1 }}>
            <CustomTypography sx={{ fontSize: 18 }}>MRP:</CustomTypography>
            <CustomTypography
              sx={{
                textDecoration: discount ? "line-through" : "none",
                fontSize: 18,
              }}
            >
              {eGlobalConstants.RUPEE_SYMBOL + bookDetails.accounting.MRP}
            </CustomTypography>
            {discount && (
              <CustomTypography sx={{ fontSize: 18, color: "red" }}>
                -{bookDetails.accounting.discount_percent}
              </CustomTypography>
            )}
          </Box>
          {discount && (
            <Box sx={{ display: "flex", gap: 1 }}>
              <CustomTypography sx={{ fontSize: 18 }}>Buy At:</CustomTypography>
              <CustomTypography sx={{ fontSize: 18 }}>
                {eGlobalConstants.RUPEE_SYMBOL +
                  bookDetails.accounting.offer_price}
              </CustomTypography>
            </Box>
          )}
        </Grid2>
        <Grid2
          size={7}
          sx={{
            display: "flex",
            justifyContent: "right",
            alignItems: "center",
            gap: 3,
          }}
        >
          <NumberStepper
            isCartOperation={isCartOperation}
            bookDetails={bookDetails}
            resetCounter={resetCounterValue}
          />
          {isCartOperation ? (
            <CustomButton
              component="IconButton"
              onClick={handleRemoveFromCart}
              sx={{
                background: "red",
                padding: 1.5,
                "&:hover": {
                  backgroundColor: "red",
                },
              }}
              title="Remove from cart"
            >
              <RemoveShoppingCartIcon sx={{ color: "white" }} />
            </CustomButton>
          ) : (
            <CustomButton
              component="IconButton"
              onClick={handleAddToCart}
              sx={{
                background: "green",
                padding: 1.5,
                "&:hover": {
                  backgroundColor: "green",
                },
              }}
              title="Add to cart"
            >
              <AddShoppingCartSharpIcon sx={{ color: "white" }} />
            </CustomButton>
          )}
        </Grid2>
      </Grid2>
    </>
  );
};
