import { Paper } from "@mui/material";
import { Box, Divider } from "@material-ui/core";

import { CustomTypography } from "components/custom_typography";
import { PriceCard } from "components/price_card";
import { BookCardProps } from "models";

interface OverviewProps {
  bookDetails: BookCardProps;
}

export const BookOverview = ({ bookDetails }: OverviewProps): JSX.Element => {
  return (
    <Box>
      <Paper sx={{ padding: 1 }}>
        <CustomTypography variant="h4" sx={{ fontFamily: "EB Garamond" }}>
          {bookDetails.title}
        </CustomTypography>
      </Paper>
      <CustomTypography
        variant="subtitle1"
        sx={{
          fontFamily: "EB Garamond",
          fontSize: 20,
          py: 3,
          height: 400,
          overflow: "auto",
        }}
      >
        {bookDetails.description}
      </CustomTypography>
      <Box>
        <Divider variant="fullWidth" />
        <PriceCard bookDetails={bookDetails} />
      </Box>
    </Box>
  );
};
