import { useState } from "react";
import { useDispatch, useSelector } from "react-redux";

import { Card, Divider } from "@material-ui/core";
import { Box, Grid2 } from "@mui/material";
import Grid from "@mui/material/Grid2";
import FavoriteIcon from "@mui/icons-material/Favorite";

import { CustomTypography } from "components/custom_typography";
import { PriceCard } from "components/price_card";
import { BookModal } from "components/book_modal";
import { BookCardProps } from "models";
import { CustomButton } from "components/custom_button";
import { RootState, setWishList } from "store";
import { eGlobalConstants, PREFIX_URL } from "global_constants";

interface Props {
  bookDetails: BookCardProps;
}

export function BookCard({ bookDetails }: Props): JSX.Element {
  const [openModal, setOpenModal] = useState(false);
  const [inWishList, setInWishList] = useState(false);
  const dispatch = useDispatch();
  const wichListSlice = useSelector(
    (state: RootState) => state.dataSlice.wishList
  );

  const handleCloseModal = () => {
    setOpenModal(false);
  };

  const IsInWishlist = (bookId: string) => {
    return (
      bookId?.length > 0 &&
      wichListSlice.find((itr: string) => itr === bookId) === bookId
    );
  };

  const BookIdNotExists = (bookId: string) => {
    return !bookId || bookId?.length <= 0;
  };

  const ToggleWishlist = (bookId: string) => {
    if (BookIdNotExists(bookId)) return;
    var list: string[] = [];
    if (!IsInWishlist(bookId)) {
      list.push(...wichListSlice, bookId);
      dispatch(setWishList(list));
      setInWishList(true);
    } else {
      list.splice(list.indexOf(bookId));
      dispatch(setWishList(list));
      setInWishList(false);
    }
  };

  return (
    <Card style={{ margin: 10, width: eGlobalConstants.CARD_WIDTH }}>
      <Grid container spacing={1}>
        <Grid size={4} display={"flex"} justifyContent={"center"}>
          <img
            src={
              PREFIX_URL +
              eGlobalConstants.BOOK_CARD_MAIN_THUMBNAIL +
              bookDetails.thumbnail
            }
            alt="book"
            style={{ width: 120, padding: 10 }}
          />
          <Divider orientation="vertical" variant="fullWidth" flexItem />
        </Grid>

        <Grid size={8}>
          <Grid container direction="column" spacing={2}>
            <Grid>
              <Box
                sx={{
                  overflow: "hidden",
                  height: 150,
                }}
              >
                <Grid2 container display={"flex"} alignItems={"center"} gap={1}>
                  <Grid2 size={10}>
                    <CustomTypography variant="subtitle1" sx={{ fontSize: 24 }}>
                      {bookDetails.title}
                    </CustomTypography>
                  </Grid2>
                  <Grid2>
                    <CustomButton component={"IconButton"}>
                      <FavoriteIcon
                        onClick={() => {
                          ToggleWishlist(bookDetails.uuid);
                        }}
                        sx={{
                          ml: 1,
                          cursor: "pointer",
                          color: inWishList ? "red" : "rgba(0,0,0,0.2)",
                          visibility: BookIdNotExists(bookDetails.uuid)
                            ? "hidden"
                            : "visible",
                        }}
                      />
                    </CustomButton>
                  </Grid2>
                </Grid2>
                <CustomTypography variant="body2" sx={{ fontSize: 16 }}>
                  {bookDetails.description}
                </CustomTypography>
              </Box>
            </Grid>
            <Grid sx={{ cursor: "pointer" }} onClick={() => setOpenModal(true)}>
              <CustomTypography
                sx={{ textAlign: "right", paddingRight: 2, color: "blue" }}
              >
                Click More Details...
              </CustomTypography>
            </Grid>
          </Grid>
        </Grid>
      </Grid>
      <Divider variant="fullWidth" />
      <PriceCard bookDetails={bookDetails} />
      {openModal && (
        <BookModal
          open={openModal}
          bookDetails={bookDetails}
          closeHandle={handleCloseModal}
        />
      )}
    </Card>
  );
}
