import { useSelector } from "react-redux";
import { Fragment, useState } from "react";

import {
  Button,
  Divider,
  Grid2,
  List,
  ListItem,
  ListItemAvatar,
  ListItemText,
  Rating,
  Stack,
  TextField,
} from "@mui/material";
import { Box, Paper } from "@material-ui/core";
import StarIcon from "@mui/icons-material/Star";

import { Review, Reviews } from "models";
import AccountCircleIcon from "@mui/icons-material/AccountCircle";
import { Paginate } from "components/pagination";
import { CustomTypography } from "components/custom_typography";
import { RootState } from "store";

interface ReviewProps {
  bookDetails: Reviews;
}

export const BookReviews = ({ bookDetails }: ReviewProps): JSX.Element => {
  const paginationSlice = useSelector(
    (state: RootState) => state.dataSlice.pagination
  );
  const [writeReview, setWriteReview] = useState(false);
  const [rating, setrating] = useState(0.0);

  const onRatingChanged = (event: any, newValue: any) => {
    setrating(newValue);
  };

  const handleSubmit = () => {
    setWriteReview(false);
  };

  return (
    <Box>
      {writeReview && (
        <Stack spacing={1} gap={3}>
          <CustomTypography variant="h4">
            Rate your Expirience
            <Divider variant="fullWidth" flexItem sx={{ mt: 2 }} />
          </CustomTypography>
          <Rating
            name="half-rating"
            defaultValue={rating}
            precision={0.5}
            size="large"
            onChange={onRatingChanged}
          />
          <TextField
            multiline
            placeholder="Write a review..."
            rows={7}
            fullWidth
          />
          <Button
            style={{
              color: "white",
              backgroundColor: "#4649ff",
              padding: 10,
              marginBottom: 15,
            }}
            onClick={handleSubmit}
          >
            <CustomTypography variant={"button"}>Submit</CustomTypography>
          </Button>
        </Stack>
      )}
      {!writeReview && (
        <Box>
          <Paper style={{ padding: 10 }}>
            <Grid2 container display={"flex"} alignItems="center">
              <Grid2 size={2.5}>
                <CustomTypography
                  variant="body1"
                  sx={{
                    fontFamily: "EB Garamond",
                    fontSize: 22,
                  }}
                >
                  Over-All Rating:
                </CustomTypography>
              </Grid2>
              <Grid2
                size={9.5}
                display={"flex"}
                justifyContent={"space-between"}
                alignItems={"center"}
              >
                <Rating
                  name="half-rating-read"
                  defaultValue={parseFloat(bookDetails.avg_rating)}
                  precision={0.5}
                  size="large"
                  readOnly
                />
                <Button
                  style={{
                    color: "white",
                    backgroundColor: "#4649ff",
                    padding: 10,
                  }}
                  onClick={() => setWriteReview(true)}
                >
                  <CustomTypography variant={"button"}>
                    Write a review
                  </CustomTypography>
                </Button>
              </Grid2>
              <Grid2></Grid2>
            </Grid2>
          </Paper>
          <List
            sx={{
              mt: 1,
              width: "100%",
              bgcolor: "background.paper",
              overflow: "auto",
              height: 400,
            }}
          >
            {bookDetails.review_list
              .slice(
                paginationSlice.page * paginationSlice.rowsPerPage,
                paginationSlice.page * paginationSlice.rowsPerPage +
                  paginationSlice.rowsPerPage
              )
              .map((review: Review, index: any) => (
                <Fragment key={index}>
                  <ListItem alignItems="center" sx={{ gap: 2 }}>
                    <ListItemAvatar>
                      <AccountCircleIcon sx={{ fontSize: 50 }} />
                    </ListItemAvatar>
                    <ListItemText
                      primary={
                        <Box>
                          <CustomTypography
                            variant="body1"
                            sx={{
                              fontFamily: "EB Garamond",
                              fontSize: 20,
                            }}
                          >
                            {review.user_name}
                          </CustomTypography>
                          <CustomTypography
                            variant="body1"
                            sx={{
                              display: "flex",
                              alignItems: "center",
                              fontFamily: "EB Garamond",
                              fontSize: 20,
                            }}
                          >
                            {review.rating}
                            <StarIcon sx={{ color: "yellow" }} />
                          </CustomTypography>
                        </Box>
                      }
                      secondary={
                        <CustomTypography
                          variant="body1"
                          sx={{
                            fontFamily: "EB Garamond",
                          }}
                        >
                          {review.review}
                        </CustomTypography>
                      }
                    />
                  </ListItem>
                  <Divider variant="fullWidth" component="li" flexItem />
                </Fragment>
              ))}
          </List>
          <Paginate count={bookDetails.review_list.length} rowsPerPage={3} />
        </Box>
      )}
    </Box>
  );
};
