import { Fragment } from "react/jsx-runtime";

import {
  Box,
  Divider,
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
} from "@mui/material";

import SettingsRoundedIcon from "@mui/icons-material/SettingsRounded";
import { CustomTypography } from "components/custom_typography";
import { ButtonProp } from "components/navbar/nav_buttons";

export const DrawerList = (
  drawer: any,
  open: boolean,
  onClose: () => void,
  onclick: () => void
) => {
  return (
    <Drawer
      open={open}
      anchor="right"
      onClose={onClose}
      sx={{
        "& .MuiDrawer-paper": {
          // background: "rgba(0,0,0,0.8)",
          // color: "white",
          // borderRadius: "40px 0 0 40px",
        },
      }}
    >
      <Box role="presentation" onClick={onclick}>
        <List>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 10,
              padding: 10,
            }}
          >
            <SettingsRoundedIcon color="primary" />
            <CustomTypography variant="button">More Options</CustomTypography>
          </div>
          <Divider />
          {drawer.options.map((value: ButtonProp, index: any) => (
            <Fragment key={index}>
              <ListItem key={index} disablePadding sx={{ mr: 15 }}>
                <ListItemButton>
                  <ListItemIcon>
                    <value.icon />
                  </ListItemIcon>
                  <ListItemText primary={value.buttonName} />
                </ListItemButton>
              </ListItem>
            </Fragment>
          ))}
        </List>
      </Box>
    </Drawer>
  );
};
