import { useState } from "react";
import { Box, Button, IconButton, SxProps } from "@mui/material";

interface CustomButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  onClick?: () => void;
  children?: JSX.Element;
  title?: string;
  sx?: SxProps;
  component: "IconButton" | "Button";
  startIcon?: React.ReactNode;
}

export const CustomButton = (props: CustomButtonProps) => {
  const [mouseClicked, setMouseClicked] = useState(false);
  const sx = {
    ...props.sx,
    transition: "ease-in 0.1s",
    transform: mouseClicked ? "scale(0.85)" : "none",
  };

  return (
    <Box
      component={props.component === "IconButton" ? IconButton : Button}
      sx={sx}
      size="small"
      title={props.title}
      onClick={props.onClick}
      onMouseDown={() => setMouseClicked(true)}
      onMouseUp={() => setMouseClicked(false)}
      disableRipple
      startIcon={props.startIcon}
    >
      {props.children}
    </Box>
  );
};
