import { useEffect, useRef, useState } from "react";

import { Divider } from "@material-ui/core";
import { Box, Card, Fab, Stack } from "@mui/material";

import { BookCardProps, CategoryContent } from "models";
import ArrowCircleRightIcon from "@mui/icons-material/ArrowCircleRight";
import ArrowCircleLeftIcon from "@mui/icons-material/ArrowCircleLeft";
import { CustomTypography } from "components/custom_typography";
import { BookCard } from "./book_card";
import { eGlobalConstants } from "global_constants";

interface Props {
  content: CategoryContent;
}

interface ArrowButtonProps {
  position: eMove;
  hide: boolean;
  clickHandle: () => void;
}

enum eMove {
  NONE,
  RIGHT,
  LEFT,
}

export function BookList({ content }: Props): JSX.Element {
  const [translateX, setTranslateX] = useState(0);
  const [visibleItems, setVisibleItems] = useState(3);
  const book_card_container = useRef<HTMLDivElement>();
  const book_title_container = useRef<HTMLDivElement>();
  const gap = 5;

  useEffect(() => {
    if (book_title_container.current)
      setVisibleItems(
        book_title_container.current.offsetWidth / eGlobalConstants.CARD_WIDTH
      );
  }, [book_title_container]);

  useEffect(() => {
    if (content.book_card_details.length >= visibleItems) {
      const totalItems = content.book_card_details.length;
      const maxTranslateX =
        totalItems * (eGlobalConstants.CARD_WIDTH + gap) -
        visibleItems * (eGlobalConstants.CARD_WIDTH + gap);
      if (translateX > 0) setTranslateX(0);
      if (Math.abs(translateX) > maxTranslateX) setTranslateX(-maxTranslateX);
    }
  }, [content.book_card_details.length, translateX, visibleItems]);

  const handleArrowClick = (move: eMove) => {
    if (move === eMove.RIGHT) {
      setTranslateX((prev) => prev - (eGlobalConstants.CARD_WIDTH + gap));
    } else if (move === eMove.LEFT) {
      setTranslateX(0);
    }
  };

  const hideRightArrow = () => {
    return (
      content.book_card_details.length <= visibleItems ||
      Math.abs(translateX) >=
        content.book_card_details.length * (eGlobalConstants.CARD_WIDTH + gap) -
          visibleItems * (eGlobalConstants.CARD_WIDTH + gap)
    );
  };

  const hideLeftArrow = () => {
    return translateX === 0;
  };

  const ArrowButton = ({ position, hide, clickHandle }: ArrowButtonProps) => (
    <Fab
      size="large"
      sx={{
        position: "absolute",
        top: "40%",
        right: position === eMove.RIGHT ? "1%" : "",
        left: position === eMove.LEFT ? "1%" : "",
        background: "rgba(108, 108, 108, 0.5)",
        visibility: hide ? "hidden" : "visble",
      }}
      onClick={clickHandle}
    >
      {position === eMove.RIGHT ? (
        <ArrowCircleRightIcon sx={{ color: "#ffffff", fontSize: 30 }} />
      ) : (
        <ArrowCircleLeftIcon sx={{ color: "#ffffff", fontSize: 30 }} />
      )}
    </Fab>
  );

  return (
    <Card sx={{ p: 4, m: 5, width: "95%" }}>
      <Box ref={book_title_container}>
        <CustomTypography
          variant="h3"
          sx={{ opacity: 0.6, fontFamily: "Oleo Script" }}
        >
          {content.title}
        </CustomTypography>
        <Divider />
        <Box
          position={"relative"}
          overflow={"hidden"}
          ref={book_card_container}
        >
          <Stack
            direction="row"
            gap={3}
            sx={{
              width: `${
                content.book_card_details.length * eGlobalConstants.CARD_WIDTH
              }px`,
              transition: "transform 0.5s ease-in-out",
              transform: `translateX(${translateX}px)`,
            }}
          >
            {content?.book_card_details?.map(
              (book: BookCardProps, index: any) => (
                <BookCard key={index} bookDetails={book} />
              )
            )}
          </Stack>
          <ArrowButton
            position={eMove.RIGHT}
            hide={hideRightArrow()}
            clickHandle={() => handleArrowClick(eMove.RIGHT)}
          />
          <ArrowButton
            position={eMove.LEFT}
            hide={hideLeftArrow()}
            clickHandle={() => handleArrowClick(eMove.LEFT)}
          />
        </Box>
      </Box>
    </Card>
  );
}
